# Auto-generated by dev iter-2 (test-writer dispatch) from docs/dev/acceptance-criteria-20260524-172805.json
# AC ID: AC-04  ac_uid: session_summary_04  type: hook

import re
from pathlib import Path

AC_UID = "session_summary_04"
AC_TYPE = "hook"

CLOSE_MD = Path(__file__).resolve().parents[3] / "commands" / "close.md"


def test_AC_04():
    """
    GIVEN: commands/close.md Step 3 CLOSE:YES path is read
    WHEN:  the session summary section is inspected
    THEN:  mandatory Session Summary section exists before rating <options>;
           covers accomplished/not accomplished/needs satisfied/not satisfied/bugs/improvement.
    """
    text = CLOSE_MD.read_text()
    # Section header present
    assert re.search(r"Session (Summary|self-summary)", text), "Session Summary section header missing"
    for token in ("accomplished", "NOT accomplished", "satisfied", "Bugs", "Improvement"):
        assert token.lower() in text.lower(), f"summary token {token!r} missing"
    # Ordering: session summary must appear BEFORE the <options> block
    summary_pos = re.search(r"Session (Summary|self-summary)", text).start()
    options_pos = text.find("<options>")
    assert summary_pos < options_pos, "Session Summary must precede <options> block"
